 export default tool({
   description:
     "通过 ACP (Agent Communication Protocol) 与 Trae Agent 交互。启动/停止 ACP Server，发现可用 Agent，执行任务或流式获取结果。ACP Server 通过 trae-cli acp serve 启动。",
   args: {
     action: tool.schema
       .enum(["start", "stop", "status", "agents", "run", "stream"])
       .describe("操作类型"),
