+    const result = await $`${cliArgs}`.quiet().cwd(PLUGIN_DIR)
     if (result.exitCode !== 0 && result.stderr) {
       process.stderr.write(result.stderr)
     }
     return {
       text: result.stdout,
     }
   },
 })

