}

async function callHook(
  script: string,
  hookType: string,
  cwd: string,
  payload?: Record<string, unknown>,
) {
  try {
    const proc = Bun.spawn(hookArgs(script, hookType), {
      cwd,
      stdout: "pipe",
      stderr: "pipe",
      stdin: payload ? new Blob([JSON.stringify(payload) + "\n"]) : undefined,
    })
    const stdout = await new Response(proc.stdout).text()
    const stderr = await new Response(proc.stderr).text()
    await proc.exited
    if (stdout) {
      console.log(`[trae:${hookType}]`, stdout.trim())
      setTimeout(() => console.log(`[trae:${hookType}]`, ""), 2500)
    }
    if (stderr) console.warn(`[trae:${hookType}]`, stderr.trim())
  } catch (e) {
    console.error(`[trae-hook:${hookType}]`, e)
  }
}

function callHookSync(
  script: string,
  hookType: string,
  cwd: string,
  payload?: Record<string, unknown>,
) {
